#include <stdio.h>
#include <stdlib.h>

// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode *left;
    struct TreeNode *right;
} TreeNode;

// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*) malloc(sizeof(TreeNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to check if there exist two elements in the BST such that their sum is equal to k
int findTarget(TreeNode* root, int k) {
    // Create a set to store the values of the nodes in the tree
    int* set = (int*) malloc(100000 * sizeof(int));
    int size = 0;

    // Function to perform inorder traversal and store the values in the set
    void inorderTraversal(TreeNode* root) {
        if (root) {
            inorderTraversal(root->left);
            set[size++] = root->val;
            inorderTraversal(root->right);
        }
    }

    inorderTraversal(root);

    // Check if k - node.val exists in the set
    for (int i = 0; i < size; i++) {
        for (int j = i + 1; j < size; j++) {
            if (set[i] + set[j] == k) {
                free(set);
                return 1;
            }
        }
    }

    free(set);
    return 0;
}

int main() {
    // Create the binary search tree
    TreeNode* root = createTreeNode(5);
    root->left = createTreeNode(3);
    root->right = createTreeNode(6);
    root->left->left = createTreeNode(2);
    root->left->right = createTreeNode(4);
    root->right->right = createTreeNode(7);

    int k = 11;
    int result = findTarget(root, k);

    if (result) {
        printf("True\n");
    } else {
        printf("False\n");
    }

    return 0;
