import java.util.*;
// This class defines a node in a Binary Search Tree
class TreeNode {
    // Value of node
    int val;
    // Left child
    TreeNode left;
    // Right child
    TreeNode right;

    // Constructor initializes node with value
    TreeNode(int x) {
        val = x;
        left = null;
        right = null;
    }
}

// This class contains the brute force solution
class Solution {
    // Function to check if there exists a pair with sum k
    public boolean findTarget(TreeNode root, int k) {
        // List stores inorder traversal values
        java.util.List<Integer> inorder = new java.util.ArrayList<>();

        // Fill list using helper function
        inorderTraversal(root, inorder);

        // Two pointers for searching in sorted list
        int left = 0;
        int right = inorder.size() - 1;

        // Loop until pointers meet
        while (left < right) {
            // Calculate sum of current pair
            int sum = inorder.get(left) + inorder.get(right);

            // If sum equals k, return true
            if (sum == k) {
                return true;
            }
            // If sum smaller, move left pointer
            else if (sum < k) {
                left++;
            }
            // If sum larger, move right pointer
            else {
                right--;
            }
        }

        // If no pair found, return false
        return false;
    }

    // Helper function to perform inorder traversal
    private void inorderTraversal(TreeNode root, java.util.List<Integer> inorder) {
        // If node is null, stop recursion
        if (root == null) return;
        // Visit left subtree
        inorderTraversal(root.left, inorder);
        // Add current node value
        inorder.add(root.val);
        // Visit right subtree
        inorderTraversal(root.right, inorder);
    }
}

